public class XHyperlinkWorkflowNotesWidget extends XAbstractHyperlinkLabelCmdValueSelWidget {   public static WidgetId ID = WidgetIdAts.XHyperlinkWorkflowNotesWidget;   private final String shortValue;   private final IAtsWorkItem workItem;   public XHyperlinkWorkflowNotesWidget() {      this("", "", null);   }   public XHyperlinkWorkflowNotesWidget(String label, String shortValue, IAtsWorkItem workItem) {      super(ID, label);      this.shortValue = shortValue;      this.workItem = workItem;   }   @Override   public String getCurrentValue() {      return shortValue;   }   @Override   public boolean handleSelection() {      EntryDialog ed = new EntryDialog(Displays.getActiveShell(), "View/Update Workflow Notes", null,         "Enter Workflow Notes", MessageDialog.QUESTION, new String[] {"Remove", "Update", "Cancel"}, 2);      ed.setFillVertically(true);      int result = ed.open();      if (result == 0 || result == 1) {         IAtsChangeSet changes = AtsApiService.get().createChangeSet("Update WF Notes");         if (result == 0) {            changes.deleteAttributes(workItem, AtsAttributeTypes.WorkflowNotes);         } else if (result == 1) {            changes.setSoleAttributeValue(workItem, AtsAttributeTypes.WorkflowNotes, ed.getEntry());         }         changes.executeIfNeeded();         return true;      }      return false;   }}